<template>
	<h2 ref="containerRef" :class="`overflow-hidden ${containerClassName}`">
		<span
			:class="`inline-block text-center leading-relaxed font-black ${textClassName}`"
			style="font-size: clamp(1.6rem, 8vw, 10rem)"
		>
			<span v-for="(char, index) in splitText" :key="index" class="inline-block char">
				{{ char === " " ? "\xA0" : char }}
			</span>
		</span>
	</h2>
</template>

<script setup>
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { computed, onMounted, onUnmounted, ref, watch } from "vue";
const props = defineProps({
  children: { type: String, required: true },
  scrollContainerRef: { type: Object, required: false },
  containerClassName: { type: String, required: false, default: "" },
  textClassName: { type: String, required: false, default: "" },
  animationDuration: { type: Number, required: false, default: 1 },
  ease: { type: String, required: false, default: "back.inOut(2)" },
  scrollStart: { type: String, required: false, default: "center bottom+=50%" },
  scrollEnd: { type: String, required: false, default: "bottom bottom-=40%" },
  stagger: { type: Number, required: false, default: 0.03 }
});
gsap.registerPlugin(ScrollTrigger);
const containerRef = ref(null);
let scrollTriggerInstance = null;
const splitText = computed(() => {
  const text = typeof props.children === "string" ? props.children : "";
  return text.split("");
});
const initializeAnimation = () => {
  const el = containerRef.value;
  if (!el) return;
  const scroller = props.scrollContainerRef && props.scrollContainerRef.current ? props.scrollContainerRef.current : window;
  const charElements = el.querySelectorAll(".char");
  if (scrollTriggerInstance) {
    scrollTriggerInstance.kill();
  }
  const tl = gsap.fromTo(
    charElements,
    {
      willChange: "opacity, transform",
      opacity: 0,
      yPercent: 120,
      scaleY: 2.3,
      scaleX: 0.7,
      transformOrigin: "50% 0%"
    },
    {
      duration: props.animationDuration,
      ease: props.ease,
      opacity: 1,
      yPercent: 0,
      scaleY: 1,
      scaleX: 1,
      stagger: props.stagger,
      scrollTrigger: {
        trigger: el,
        scroller,
        start: props.scrollStart,
        end: props.scrollEnd,
        scrub: true
      }
    }
  );
  scrollTriggerInstance = tl.scrollTrigger || null;
};
onMounted(() => {
  initializeAnimation();
});
onUnmounted(() => {
  if (scrollTriggerInstance) {
    scrollTriggerInstance.kill();
  }
});
watch(
  [
    () => props.children,
    () => props.scrollContainerRef,
    () => props.animationDuration,
    () => props.ease,
    () => props.scrollStart,
    () => props.scrollEnd,
    () => props.stagger
  ],
  () => {
    initializeAnimation();
  },
  { deep: true }
);
</script>
